import "core-js/modules/esnext.iterator.constructor.js";
import "core-js/modules/esnext.iterator.for-each.js";
import { ref, computed, watch } from 'vue';
import { PlusIcon, PencilSquareIcon, MinusCircleIcon, ChevronUpIcon, ChevronDownIcon } from '@heroicons/vue/24/outline';

// 导入各个模块的内容组件
import BasicInfo from './BasicInfo.vue';
import JobIntentionContent from './JobIntentionContent.vue';
import WorkExperienceContent from './WorkExperienceContent.vue';
import EducationContent from './EducationContent.vue';
import ProjectContent from './ProjectContent.vue';
import SkillContent from './SkillContent.vue';
import CertificateContent from './CertificateContent.vue';
import LanguageContent from './LanguageContent.vue';
import PortfolioContent from './PortfolioContent.vue';
import SocialLinkContent from './SocialLinkContent.vue';
export default {
  __name: 'ModuleList',
  props: {
    activeModules: {
      type: Array,
      default: () => []
    },
    inactiveModules: {
      type: Array,
      default: () => []
    }
  },
  setup(__props, {
    expose: __expose
  }) {
    __expose();
    const props = __props;

    // 添加布局相关的计算属性
    const sortedActiveModules = computed(() => {
      return [...props.activeModules].sort((a, b) => {
        const orderA = a.order || 999;
        const orderB = b.order || 999;
        return orderA - orderB;
      });
    });

    // 获取组件映射
    const getComponentByType = type => {
      const componentMap = {
        'basic_info': BasicInfo,
        'job_intention': JobIntentionContent,
        'work_experience': WorkExperienceContent,
        'education': EducationContent,
        'project': ProjectContent,
        'skill': SkillContent,
        'certificate': CertificateContent,
        'language': LanguageContent,
        'portfolio': PortfolioContent,
        'social_link': SocialLinkContent
      };
      return componentMap[type];
    };

    // 获取模块名称
    const getModuleName = type => {
      const moduleNames = {
        'basic_info': '基本信息',
        'job_intention': '求职意向',
        'work_experience': '工作经历',
        'education': '教育经历',
        'project': '项目经历',
        'skill': '专业技能',
        'certificate': '证书奖项',
        'language': '语言能力',
        'portfolio': '作品展示',
        'social_link': '社交主页'
      };
      return moduleNames[type] || type;
    };

    // 判断是否显示添加按钮
    const shouldShowAddButton = type => {
      // 基本信息和求职意向只能有一条记录
      if (type === 'basic_info' || type === 'job_intention') {
        return false;
      }
      return true;
    };

    // 获取组件 props 的方法
    const getComponentProps = module => {
      console.log('ModuleList getComponentProps:', module.type, module.data);
      switch (module.type) {
        case 'basic_info':
          return {
            resumeData: module.data,
            loading: props.loading,
            bioExpanded: false,
            showBioExpandButton: false
          };
        case 'job_intention':
          console.log('Job intention data:', module.data);
          return {
            data: module.data
          };
        case 'work_experience':
        case 'education':
        case 'project':
        case 'skill':
        case 'certificate':
        case 'language':
        case 'portfolio':
        case 'social_link':
          return {
            data: module.data
          };
        default:
          return {
            data: module.data
          };
      }
    };

    // 模块展开状态管理
    const expandedModules = ref({});

    // 初始化所有模块为展开状态
    const initExpandedState = modules => {
      modules.forEach(module => {
        if (expandedModules.value[module.type] === undefined) {
          expandedModules.value[module.type] = true;
        }
      });
    };

    // 监听 activeModules 变化，初始化展开状态
    watch(() => props.activeModules, newModules => {
      if (newModules) {
        initExpandedState(newModules);
      }
    }, {
      immediate: true
    });

    // 切换模块展开状态
    const toggleModule = type => {
      expandedModules.value[type] = !expandedModules.value[type];
    };
    const __returned__ = {
      props,
      sortedActiveModules,
      getComponentByType,
      getModuleName,
      shouldShowAddButton,
      getComponentProps,
      expandedModules,
      initExpandedState,
      toggleModule,
      ref,
      computed,
      watch,
      get PlusIcon() {
        return PlusIcon;
      },
      get PencilSquareIcon() {
        return PencilSquareIcon;
      },
      get MinusCircleIcon() {
        return MinusCircleIcon;
      },
      get ChevronUpIcon() {
        return ChevronUpIcon;
      },
      get ChevronDownIcon() {
        return ChevronDownIcon;
      },
      BasicInfo,
      JobIntentionContent,
      WorkExperienceContent,
      EducationContent,
      ProjectContent,
      SkillContent,
      CertificateContent,
      LanguageContent,
      PortfolioContent,
      SocialLinkContent
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
